const cfg = $('Config').first().json;
const SUPABASE_URL = cfg.SUPABASE_URL;
const SUPABASE_SERVICE_KEY = cfg.SUPABASE_SERVICE_KEY;
const RESEND_API_KEY = cfg.RESEND_API_KEY;
const DEFAULT_FROM_EMAIL = cfg.DEFAULT_FROM_EMAIL;

const headers = {
  apikey: SUPABASE_SERVICE_KEY,
  Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`,
};

const jsonHeaders = {
  ...headers,
  'Content-Type': 'application/json',
};

const now = new Date();

const formatDateInTimezone = (date, timezone) => {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(date);
  const map = Object.fromEntries(parts.map((p) => [p.type, p.value]));
  return `${map.year}-${map.month}-${map.day}`;
};

const getLocalHourMinute = (date, timezone) => {
  const parts = new Intl.DateTimeFormat('en-GB', {
    timeZone: timezone,
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  }).formatToParts(date);
  const map = Object.fromEntries(parts.map((p) => [p.type, p.value]));
  return { hour: Number(map.hour), minute: Number(map.minute) };
};

const addDays = (yyyyMmDd, days) => {
  const dt = new Date(`${yyyyMmDd}T12:00:00Z`);
  dt.setUTCDate(dt.getUTCDate() + days);
  return dt.toISOString().slice(0, 10);
};

const deltaPct = (curr, prev) => {
  if (prev === null || prev === undefined || Number(prev) === 0) return null;
  return ((Number(curr) - Number(prev)) / Number(prev)) * 100;
};

const fmtPct = (value) => {
  if (value === null || value === undefined) return '-';
  return `${value >= 0 ? '+' : ''}${value.toFixed(1)}%`;
};

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const fetchJson = async (url, options = {}) => {
  const res = await fetch(url, options);
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`${res.status} ${res.statusText} :: ${text}`);
  }
  return res.json();
};

const configsUrl = `${SUPABASE_URL}/rest/v1/ad_report_configs?select=id,organization_id,meta_ad_account_id,is_enabled,send_time_local,report_timezone,from_email,from_name,subject_template,recipient_emails,organizations!organization_id(id,name),meta_ad_accounts!meta_ad_account_id(id,account_name,meta_ad_account_id,access_token_ref,report_timezone,is_active)&is_enabled=eq.true&is_active=eq.true`;
const configs = await fetchJson(configsUrl, { headers });

if (!Array.isArray(configs) || configs.length === 0) {
  return [{ json: { processed: 0, result: 'no_active_configs' } }];
}

const results = [];

for (const config of configs) {
  const timezone = config.report_timezone || config.meta_ad_accounts?.report_timezone || 'Europe/Istanbul';
  const localTime = getLocalHourMinute(now, timezone);
  const targetTime = String(config.send_time_local || '00:15').slice(0, 5);
  const [targetHour, targetMinute] = targetTime.split(':').map(Number);

  if (localTime.hour !== targetHour || localTime.minute !== targetMinute) {
    results.push({
      organization_id: config.organization_id,
      account_row_id: config.meta_ad_accounts?.id,
      skipped: `waiting_for_schedule_${targetTime}`,
    });
    continue;
  }

  try {
    const todayLocal = formatDateInTimezone(now, timezone);
    const reportDate = addDays(todayLocal, -1);
    const periodStart = `${reportDate}T00:00:00`;
    const periodEnd = `${reportDate}T23:59:59`;
    const accountNumericId = String(config.meta_ad_accounts.meta_ad_account_id || '').replace(/^act_/, '');
    const metaApiAccountId = `act_${accountNumericId}`;
    const accessToken = config.meta_ad_accounts.access_token_ref;

    const existingRunUrl = `${SUPABASE_URL}/rest/v1/ad_report_runs?select=id,status&period_label=eq.${reportDate}&meta_ad_account_id=eq.${config.meta_ad_accounts.id}&limit=1`;
    const existingRun = await fetchJson(existingRunUrl, { headers });
    if (Array.isArray(existingRun) && existingRun.length > 0) {
      results.push({
        organization_id: config.organization_id,
        account_row_id: config.meta_ad_accounts.id,
        skipped: `already_processed_${reportDate}`,
      });
      continue;
    }

    const metaUrl = `https://graph.facebook.com/v23.0/${metaApiAccountId}/insights?level=campaign&fields=campaign_name,spend,impressions,clicks,ctr,cpc,cpm,actions,action_values,purchase_roas&time_range=${encodeURIComponent(JSON.stringify({ since: reportDate, until: reportDate }))}&access_token=${encodeURIComponent(accessToken)}`;
    const metaData = await fetchJson(metaUrl);
    const rows = Array.isArray(metaData.data) ? metaData.data : [];

    const totals = rows.reduce((acc, row) => ({
      spend: acc.spend + Number(row.spend || 0),
      impressions: acc.impressions + Number(row.impressions || 0),
      clicks: acc.clicks + Number(row.clicks || 0),
    }), { spend: 0, impressions: 0, clicks: 0 });

    const ctr = totals.impressions ? (totals.clicks / totals.impressions) * 100 : 0;
    const cpc = totals.clicks ? totals.spend / totals.clicks : 0;
    const metrics = { ...totals, ctr, cpc };
    const topCampaign = [...rows].sort((a, b) => Number(b.spend || 0) - Number(a.spend || 0))[0] || null;

    const previousRunUrl = `${SUPABASE_URL}/rest/v1/ad_report_runs?select=id,metrics,period_label,status&meta_ad_account_id=eq.${config.meta_ad_accounts.id}&status=eq.sent&order=period_start.desc&limit=1`;
    const previousRuns = await fetchJson(previousRunUrl, { headers });
    const previousRun = Array.isArray(previousRuns) && previousRuns.length ? previousRuns[0] : null;
    const prevMetrics = previousRun?.metrics || null;

    const comparison = prevMetrics ? {
      spend_pct: deltaPct(metrics.spend, prevMetrics.spend),
      impressions_pct: deltaPct(metrics.impressions, prevMetrics.impressions),
      clicks_pct: deltaPct(metrics.clicks, prevMetrics.clicks),
      ctr_pct: deltaPct(metrics.ctr, prevMetrics.ctr),
      cpc_pct: deltaPct(metrics.cpc, prevMetrics.cpc),
    } : null;

    const reportHtml = `
      <div style="font-family:Arial,sans-serif;line-height:1.5;color:#111">
        <h2>${escapeHtml(config.organizations?.name || 'Organization')} - Meta Ads Gunluk Rapor</h2>
        <p>Tarih: ${escapeHtml(reportDate)}</p>
        <ul>
          <li>Harcama: ${metrics.spend.toFixed(2)}</li>
          <li>Gosterim: ${metrics.impressions}</li>
          <li>Tiklama: ${metrics.clicks}</li>
          <li>CTR: ${metrics.ctr.toFixed(2)}%</li>
          <li>CPC: ${metrics.cpc.toFixed(2)}</li>
        </ul>
        ${topCampaign ? `<p>En cok harcama yapan kampanya: <strong>${escapeHtml(topCampaign.campaign_name)}</strong></p>` : '<p>Kampanya verisi yok.</p>'}
        ${comparison ? `
          <h3>Onceki Raporla Kiyas</h3>
          <ul>
            <li>Harcama: ${fmtPct(comparison.spend_pct)}</li>
            <li>Gosterim: ${fmtPct(comparison.impressions_pct)}</li>
            <li>Tiklama: ${fmtPct(comparison.clicks_pct)}</li>
            <li>CTR: ${fmtPct(comparison.ctr_pct)}</li>
            <li>CPC: ${fmtPct(comparison.cpc_pct)}</li>
          </ul>
        ` : '<p>Ilk rapor oldugu icin onceki veriyle kiyas yapilmadi.</p>'}
      </div>
    `;

    const insertPayload = {
      organization_id: config.organization_id,
      meta_ad_account_id: config.meta_ad_accounts.id,
      config_id: config.id,
      provider: 'meta_ads',
      period_start: periodStart,
      period_end: periodEnd,
      period_label: reportDate,
      status: 'processing',
      metrics,
      summary: {
        top_campaign: topCampaign,
        comparison,
        previous_run_id: previousRun?.id || null,
      },
      report_html: reportHtml,
    };

    await fetchJson(`${SUPABASE_URL}/rest/v1/ad_report_runs`, {
      method: 'POST',
      headers: {
        ...jsonHeaders,
        Prefer: 'resolution=merge-duplicates,return=minimal',
      },
      body: JSON.stringify(insertPayload),
    });

    const resendPayload = {
      from: `${config.from_name || 'stoaix Reports'} <${config.from_email || DEFAULT_FROM_EMAIL}>`,
      to: config.recipient_emails,
      subject: `${config.organizations?.name || 'Organization'} - Meta Ads gunluk raporu (${reportDate})`,
      html: reportHtml,
    };

    const resendRes = await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${RESEND_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(resendPayload),
    });

    const resendText = await resendRes.text();
    if (!resendRes.ok) {
      await fetch(`${SUPABASE_URL}/rest/v1/ad_report_runs?meta_ad_account_id=eq.${config.meta_ad_accounts.id}&period_label=eq.${reportDate}`, {
        method: 'PATCH',
        headers: jsonHeaders,
        body: JSON.stringify({ status: 'failed', error_message: resendText }),
      });
      throw new Error(`Resend failed: ${resendText}`);
    }

    let resendJson = {};
    try { resendJson = JSON.parse(resendText); } catch {}

    await fetch(`${SUPABASE_URL}/rest/v1/ad_report_runs?meta_ad_account_id=eq.${config.meta_ad_accounts.id}&period_label=eq.${reportDate}`, {
      method: 'PATCH',
      headers: jsonHeaders,
      body: JSON.stringify({
        status: 'sent',
        email_provider: 'resend',
        email_id: resendJson.id || null,
        sent_at: new Date().toISOString(),
      }),
    });

    results.push({
      organization_id: config.organization_id,
      account_row_id: config.meta_ad_accounts.id,
      report_date: reportDate,
      status: 'sent',
    });
  } catch (error) {
    results.push({
      organization_id: config.organization_id,
      account_row_id: config.meta_ad_accounts?.id,
      status: 'error',
      error: error.message,
    });
  }
}

return [{ json: { processed: results.length, results } }];
